library ieee;
  use ieee.std_logic_1164.all;
  use ieee.numeric_std.all;
  use work.cpu_defs_pkg.all;

entity fetch_stage is
  port (
    clk : in    std_logic;
    rst : in    std_logic;

    -- signals inputs
    stall                   : in    std_logic;
    mem_to_pc_enable_in     : in    std_logic;
    jump_taken_from_execute : in    std_logic;
    jump_taken_from_decode  : in    std_logic;

    -- data inputs
    jump_pc_in  : in    std_logic_vector(DATA_WIDTH - 1 downto 0); -- target pc  for jump (from decode)
    mem_data_in : in    std_logic_vector(DATA_WIDTH - 1 downto 0); -- pc read from memory

    -- data outputs
    pc_out_plus_1 : out   std_logic_vector(DATA_WIDTH - 1 downto 0); -- propagate
    pc_out        : out   std_logic_vector(DATA_WIDTH - 1 downto 0)  -- access the next fetch from mem
  );
end entity fetch_stage;

architecture fetch_stage_arch of fetch_stage is

  -- Internal signals
  signal jump_take   : std_logic;
  signal pc_reg      : std_logic_vector(DATA_WIDTH - 1 downto 0) := (others => '0');
  signal pc_plus_1_s : std_logic_vector(DATA_WIDTH - 1 downto 0);
  signal pc_next     : std_logic_vector(DATA_WIDTH - 1 downto 0);

begin

  -- Compute pc + 1
  pc_plus_1_s <= std_logic_vector(unsigned(pc_reg) + 1);

  jump_take   <= jump_taken_from_execute or jump_taken_from_decode;

  u_prio : entity work.priority_pc_mux
    port map (
      rst              => rst,
      mem_to_pc_enable => mem_to_pc_enable_in,
      stall            => stall,
      jump_take        => jump_take,
      mem_pc           => mem_data_in,
      jump_pc          => jump_pc_in,
      current_pc       => pc_reg,
      pc_plus_1        => pc_plus_1_s,
      pc_next          => pc_next
    );

  -- PC register process
  process (clk, rst) is
  begin

    if (rst = '1') then
      pc_reg <= (others => '0'); -- async reset to zero
    elsif rising_edge(clk) then
      pc_reg <= pc_next;
    end if;

  end process;

  pc_out        <= pc_reg;
  pc_out_plus_1 <= pc_plus_1_s;

end architecture fetch_stage_arch;
